    if not isinstance(path, str) or not path or path.startswith('/') or chr(92) in path or chr(0) in path: raise ValueError('invalid path')
    parts = []
    for part in path.split('/'):
        if part in ('', '.'): continue
        if part == '..':
            if not parts: raise ValueError('path escapes root')
            parts.pop()
